        + indexLabel.intrinsicContentSize.width
        + Self.zoomGap

    let fullText = ZoomStatusFormatter.text(for: zoomMode, style: .full)
    cachedRegularThreshold = coreWidth + textWidth(fullText, font: font) + Self.contentPadding

